const https = require('https');

function httpReq(url, options = {}) {
  return new Promise((resolve, reject) => {
    const m = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!m) { reject(new Error('Invalid URL: ' + url)); return; }
    const hostname = m[1];
    const path = m[2] || '/';
    const postData = options.body || '';
    const req = https.request({
      hostname: hostname,
      port: 443,
      path: path,
      method: options.method || 'GET',
      headers: { ...options.headers, ...(postData ? { 'Content-Length': Buffer.byteLength(postData) } : {}) }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const body = Buffer.concat(chunks).toString();
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, text: () => Promise.resolve(body), json: () => Promise.resolve(JSON.parse(body)), headers: res.headers });
      });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('Request timeout')); });
    if (postData) req.write(postData);
    req.end();
  });
}

const SUPABASE_URL = 'https://prometeix-servidor-supabase.reyl9a.easypanel.host/rest/v1';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJzZXJ2aWNlX3JvbGUiLAogICAgImlzcyI6ICJzdXBhYmFzZS1kZW1vIiwKICAgICJpYXQiOiAxNjQxNzY5MjAwLAogICAgImV4cCI6IDE3OTk1MzU2MDAKfQ.DaYlNEoUrrEn2Ig7tqibS-PHK5vgusbcbo7X36XVt4Q';
const sbHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' };

const input = $input.first().json;
const body = input.body || {};

// 1. Validate token
if (!body.token) {
  return [{ json: { success: false, error: 'Token is required' } }];
}

try {
  // 2. Auth verification
  const authResp = await httpReq('https://api.katalync.com/webhook/auth-verify', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token: body.token })
  });
  const authData = await authResp.json();
  if (!authData.success) {
    return [{ json: { success: false, error: authData.error || 'Token invalid or expired' } }];
  }

  // 3. Validate required fields
  if (!body.name || !body.name.trim()) {
    return [{ json: { success: false, error: 'Vendor name is required' } }];
  }

  const validSources = ['shopify', 'woocommerce', 'prestashop', 'api', 'excel'];
  if (!body.source || !validSources.includes(body.source)) {
    return [{ json: { success: false, error: 'Source must be one of: ' + validSources.join(', ') } }];
  }

  // 4. Upsert user into Supabase
  const upsertResp = await httpReq(SUPABASE_URL + '/users?on_conflict=email', {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'resolution=merge-duplicates,return=representation' },
    body: JSON.stringify([{
      email: authData.email,
      name: authData.name || authData.email,
      password_hash: 'oauth-managed',
      role: authData.role || 'user',
      company: authData.company || null,
      lang: authData.lang || 'es',
      onboarded: authData.onboarded || false,
      subscription_status: authData.subscription_status || 'active',
      last_login_at: new Date().toISOString()
    }])
  });
  const upsertData = await upsertResp.json();
  const user_id = upsertData && upsertData.length > 0 ? upsertData[0].id : null;
  if (!user_id) {
    return [{ json: { success: false, error: 'Failed to provision user' } }];
  }

  // 5. Build vendor data
  const vendorData = {
    user_id: user_id,
    name: body.name.trim(),
    company: (body.company || '').trim() || null,
    source: body.source,
    source_url: (body.source_url || '').trim() || null,
    source_api_key: (body.source_api_key || '').trim() || null,
    source_api_secret: (body.source_api_secret || '').trim() || null,
    marketplace_id: (body.marketplace_id || '').trim() || null,
    marketplace_api_key: (body.marketplace_api_key || '').trim() || null,
    marketplace_url: (body.marketplace_url || '').trim() || null,
    sync_interval_hours: parseInt(body.sync_interval_hours) || 24,
    sync_status: 'pending',
    config: { ...(body.config || {}), marketplaces: body.marketplaces || ['sprinter_es'] }
  };

  // 6. Insert vendor into Supabase
  const createResp = await httpReq(SUPABASE_URL + '/vendors', {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=representation' },
    body: JSON.stringify(vendorData)
  });
  if (!createResp.ok) {
    const errText = await createResp.text();
    return [{ json: { success: false, error: 'Failed to create vendor: ' + errText } }];
  }
  const created = await createResp.json();
  const vendor = Array.isArray(created) ? created[0] : created;

  if (!vendor || !vendor.id) {
    return [{ json: { success: false, error: 'Vendor created but no data returned' } }];
  }

  // 7. Optional: test source connection for Shopify/WooCommerce
  let connectionTest = 'skipped';
  let connectionError = null;
  const sourceUrl = (body.source_url || '').trim();
  const apiKey = (body.source_api_key || '').trim();
  const apiSecret = (body.source_api_secret || '').trim();

  if (sourceUrl && apiKey && ['shopify', 'woocommerce'].includes(body.source)) {
    try {
      let testUrl, testHeaders;
      const cleanUrl = sourceUrl.replace(/\/+$/, '');

      if (body.source === 'shopify') {
        testUrl = cleanUrl + '/admin/api/2024-01/shop.json';
        testHeaders = { 'X-Shopify-Access-Token': apiKey };
      } else if (body.source === 'woocommerce') {
        testUrl = cleanUrl + '/wp-json/wc/v3/system_status';
        const basicAuth = Buffer.from(apiKey + ':' + apiSecret).toString('base64');
        testHeaders = { 'Authorization': 'Basic ' + basicAuth };
      }

      if (testUrl) {
        const testResp = await httpReq(testUrl, { method: 'GET', headers: testHeaders });
        if (testResp.ok) {
          connectionTest = 'ok';
          // Update vendor sync_status to active
          await httpReq(SUPABASE_URL + '/vendors?id=eq.' + vendor.id, {
            method: 'PATCH',
            headers: { ...sbHeaders, 'Prefer': 'return=representation' },
            body: JSON.stringify({ sync_status: 'active' })
          });
          vendor.sync_status = 'active';
        } else {
          connectionTest = 'failed';
          connectionError = 'HTTP ' + testResp.status;
        }
      }
    } catch (e) {
      connectionTest = 'failed';
      connectionError = e.message;
    }
  }

  // 8. Build response
  const response = { success: true, vendor: vendor, connection_test: connectionTest };
  if (connectionError) {
    response.connection_error = connectionError;
  }
  return [{ json: response }];

} catch (e) {
  return [{ json: { success: false, error: 'Server error: ' + e.message } }];
}
